mapper.select:
SELECT c.*, p.project_name FROM elder_customer c LEFT JOIN elder_project p ON p.id = c.project_id WHERE c.del_flag = 0
AND c.project_id IN (
#{id}
)
AND c.project_id = #{data.projectId}
AND c.`name` LIKE concat(concat('%',#{data.name}),'%')
AND c.phone LIKE concat(concat('%',#{data.phone}),'%')
AND c.id IN ( SELECT DISTINCT r.customer_id FROM elder_room_reserve r WHERE r.`status` = #{data.reserveStatus} )
AND c.id IN ( SELECT DISTINCT cc.customer_id FROM elder_customer_checkin cc WHERE cc.`status` = #{data.checkinStatus})
ORDER BY c.create_time DESC
